/** user-defined types **/

/**
 * Result of `test_agent_binary`: whether the binary ran and its version output.
 */
export type AgentBinaryTest = { ok: boolean; output: string; hint: AgentBinaryHint | null }
/**
 * Classified, actionable failure modes surfaced by `test_agent_binary`. The
 * frontend renders a localized fix for each instead of a raw spawn stack.
 */
export type AgentBinaryHint = "codex_vendor_missing"
/**
 * Which local coding-agent CLI a `Cli` agent drives. Selects the prefilled
 * invocation template (see `default_command_template_for`). `Custom` is a
 * fully user-defined template for any other binary.
 */
export type AgentCliType = "claude" | "codex" | "openclaw" | "hermes" | "custom"
/**
 * A Flow OS agent: dictation routed through a persona LLM before injection.
 * Each agent has its own global hotkey (via a seeded `ShortcutBinding` keyed
 * `agent:<id>`). All optional fields are `#[serde(default)]` so an old settings
 * store (with no `agents` key, or partial entries) always deserializes cleanly —
 * the store wipes to defaults on any parse failure.
 */
export type AgentDefinition = { 
/**
 * Stable slug, e.g. "coder"; unique. Matches `^[a-z0-9_-]{1,48}$`.
 */
id: string; 
/**
 * Display name shown in the UI.
 */
name: string; enabled?: boolean; 
/**
 * ALWAYS `"agent:<id>"` — the join key into `AppSettings.bindings`.
 */
binding_id: string; 
/**
 * References an existing `post_process_providers` entry.
 */
provider_id: string; model?: string; 
/**
 * The persona used as the LLM system prompt.
 */
system_prompt?: string; output_mode?: AgentOutputMode; 
/**
 * Discriminator. `Prompt` (default) → increment-1 persona-LLM behavior,
 * unchanged. `Cli` → drive a real coding-agent subprocess (fields below).
 */
kind?: AgentKind; 
/**
 * Which coding CLI this agent drives (only meaningful when `kind == Cli`).
 */
cli_type?: AgentCliType | null; 
/**
 * Resolved/overridable path to the agent binary (e.g. `/usr/local/bin/claude`).
 */
binary_path?: string; 
/**
 * Argv template appended after the binary; supports `{cwd}`/`{prompt}`
 * placeholders (see `AgentRunManager::build_argv`). Prefilled per `cli_type`.
 */
command_template?: string; 
/**
 * Project folder the agent runs in (`cwd`). `""` = no fixed project (a
 * sensible default dir is used at run time).
 */
project_path?: string; 
/**
 * Where run output goes. Defaults to `[Panel]` (live in-app stream only).
 */
output_sinks?: AgentOutputSink[]; 
/**
 * How the instruction reaches the CLI. `Stdin` (default) or `Arg`.
 */
prompt_via?: PromptDelivery }
/**
 * Flow OS increment 2 — what KIND of agent this is. `Prompt` is the increment-1
 * behavior (dictation routed through a persona LLM before injection). `Cli`
 * drives a REAL local coding-agent binary (Claude Code, Codex, …) as a
 * subprocess in a chosen project folder. Defaults to `Prompt` so every agent
 * stored before this field existed stays a prompt agent, byte-for-byte.
 */
export type AgentKind = "prompt" | "cli"
/**
 * What an agent does with its LLM response. `Inject` pastes it at the cursor
 * exactly like a normal dictation; `Clipboard` only copies it (no paste, no
 * auto-submit) and shows a brief confirmation. Defaults to `Inject`.
 */
export type AgentOutputMode = "inject" | "clipboard"
/**
 * Where a CLI agent run's output goes (multi-select). `Panel` is the live
 * streamed in-app view (always effectively on for a running view). `Notify`
 * fires a desktop notification on completion. `File` writes the full
 * instruction+output to a markdown file in the project.
 */
export type AgentOutputSink = "panel" | "notify" | "file"
/**
 * A snapshot of a run for the frontend (`list_agent_runs`).
 */
export type AgentRunInfo = { run_id: string; agent_id: string; agent_name: string; project_path: string; status: RunStatus; 
/**
 * RFC3339 local start time (for display).
 */
started_at: string; 
/**
 * Epoch milliseconds — for stable sorting and elapsed-time computation.
 */
started_at_ms: number; 
/**
 * Rolling (capped) combined stdout+stderr buffer.
 */
output: string; 
/**
 * The instruction (transcript) that drove the run.
 */
instruction: string; 
/**
 * Absolute path to the written run file, once the File sink has run.
 */
output_file: string | null }
/**
 * Emitted per output line while a run streams. Event name: `agent-run-output`.
 */
export type AgentRunOutput = { run_id: string; chunk: string }
/**
 * Emitted when a run reaches a terminal status. Event name: `agent-run-status`.
 */
export type AgentRunStatus = { run_id: string; status: RunStatus }
/**
 * Result of the agent "Test" action: the LLM's output plus how long it took.
 * Mirrors `BackendTestResult` / `test_cleanup_backend`.
 */
export type AgentTestResult = { output: string; latency_ms: number }
/**
 * A user-defined **AI Mode**: a named dictation profile with its own optional
 * global hotkey and optional per-app auto-selection rules. Modes generalize the
 * built-in cleanup ("Write") path — see [`AiModeKind`]. Every field beyond
 * `id`/`name`/`binding_id` is `#[serde(default)]` so an old settings store (no
 * `ai_modes` key, or partial entries) always deserializes cleanly; with
 * `ai_modes` empty the app behaves byte-for-byte as before this field existed.
 */
export type AiMode = { 
/**
 * Stable slug, e.g. "translate"; unique. Matches `^[a-z0-9_-]{1,48}$`.
 */
id: string; 
/**
 * Display name shown in the UI.
 */
name: string; 
/**
 * What this mode does to the transcript. Defaults to `Rewrite`.
 */
kind?: AiModeKind; enabled?: boolean; 
/**
 * ALWAYS `"mode:<id>"` — the join key into `AppSettings.bindings`.
 */
binding_id: string; 
/**
 * The editable prompt *body* (tone/instructions). Appended to a fixed hidden
 * base prompt at call time; empty for `Direct`.
 */
prompt?: string; 
/**
 * Optional provider override. `None`/empty → inherit the active cleanup
 * provider (`active_post_process_provider`).
 */
provider_id?: string | null; 
/**
 * Optional model override. `None`/empty → inherit the provider's configured
 * cleanup model (`post_process_models[provider_id]`).
 */
model?: string | null; 
/**
 * Bundle-id or app-name substrings for per-app auto-selection on the MAIN
 * hotkey. Empty → this mode is never auto-selected (hotkey-only). Matching is
 * case-insensitive substring both directions against the frontmost app's
 * bundle id AND localized name (same semantics as `per_app_prompts`).
 */
app_rules?: string[] }
/**
 * What an AI Mode does with the raw transcript before it reaches the cursor.
 * 
 * - `Rewrite` (default): route the transcript through a cleanup-style LLM using
 * the mode's editable prompt as the tone/instruction body (on top of a fixed,
 * hidden base prompt). This generalizes the existing post-process cleanup.
 * - `Command`: ask the LLM to translate the spoken request into a single bare
 * shell command via structured output, then TYPE it at the cursor. It is
 * NEVER executed and auto-submit is force-disabled for the injection.
 * - `Direct`: inject the raw transcript verbatim, skipping the LLM entirely.
 * 
 * Defaults to `Rewrite` so any partial/older stored mode deserializes as a
 * plain rewrite mode.
 */
export type AiModeKind = "rewrite" | "command" | "direct"
/**
 * Result of the AI mode "Test" action: the transformed output plus how long it
 * took. Mirrors `AgentTestResult` / `test_agent`.
 */
export type AiModeTestResult = { output: string; latency_ms: number }
/**
 * The wire protocol an HTTP STT endpoint speaks. Most providers and
 * self-hosted servers (OpenAI, Groq, Speaches, whisper-server, LocalAI) use the
 * OpenAI `/audio/transcriptions` multipart shape; Deepgram is different enough
 * to need its own adapter.
 * How much of each dictation the analytics backend persists. `Full` stores
 * everything; `KeywordsOnly` keeps derived keywords but nulls raw/cleaned text
 * and window titles; `Off` skips logging entirely.
 */
export type AnalyticsPrivacy = "full" | "keywords_only" | "off"
export type AnalyticsSummary = { total_dictations: number; total_words: number; avg_wpm: number; time_saved_seconds: number; current_streak_days: number; active_apps_count: number }
